let sum = 0, sign = 1;
for (let k = 0; k < n; k++) { sum += sign / (2 * k + 1); sign = -sign; }
console.log((sum * 4).toFixed(15));

const n = parseInt(process.argv[2]);
let count = 0;
for (let y = 0; y < n; y++) for (let x = 0; x < n; x++) {
    const cr = 2*x/n - 1.5, ci = 2*y/n - 1;
    let zr = 0, zi = 0, inside = true;
    for (let i = 0; i < 50; i++) {
        const t = zr*zr - zi*zi + cr; zi = 2*zr*zi + ci; zr = t;
        if (zr*zr + zi*zi > 4) { inside = false; break; }
    }
    if (inside) count++;
}
console.log(count);

function fib(n) {
    if (n < 2) return n;
    return fib(n - 1) + fib(n - 2);
}

const n = parseInt(process.argv[2]);
console.log(fib(n));

