console.log(sum);

const n = parseInt(process.argv[2]);
const arr = new Array(n);
let seed = 42;
for (let i = 0; i < n; i++) {
    seed = ((Math.imul(seed, 1103515245) + 12345) >>> 0) % 2147483648;
    arr[i] = (seed >> 16) % 1000;
}
const counts = new Array(1000).fill(0);
for (const v of arr) counts[v]++;
const sorted = [];
for (let v = 0; v < 1000; v++)
    for (let c = 0; c < counts[v]; c++)
        sorted.push(v);
let checksum = 0;
for (const v of sorted) checksum = (checksum + v) % 1000000007;
console.log(`${sorted[0]} ${sorted[n - 1]} ${checksum}`);

function siftDown(arr, start, end) {
    let root = start;
    while (2 * root + 1 <= end) {
        let child = 2 * root + 1;
        let swap = root;
        if (arr[swap] < arr[child]) swap = child;
        if (child + 1 <= end && arr[swap] < arr[child + 1]) swap = child + 1;
        if (swap === root) return;
        [arr[root], arr[swap]] = [arr[swap], arr[root]];
        root = swap;
    }
}
const n = parseInt(process.argv[2]);
const arr = new Array(n);
let seed = 42;
for (let i = 0; i < n; i++) { seed = ((Math.imul(seed, 1103515245) + 12345) >>> 0) % 2147483648; arr[i] = (seed>>16)&0x7fff; }
for (let s = Math.floor((n-2)/2); s >= 0; s--) siftDown(arr, s, n-1);
for (let end = n-1; end > 0; end--) { [arr[0], arr[end]] = [arr[end], arr[0]]; siftDown(arr, 0, end-1); }
let checksum = 0;
for (const v of arr) checksum = (checksum + v) % 1000000007;
console.log(`${arr[0]} ${arr[n-1]} ${checksum}`);
